module.render:
    const columns = args.columns || '2';
    let html = `\n\n<div class="mdp-mod-gallery" style="grid-template-columns: repeat(${columns}, 1fr);">\n`;
    sections.forEach((section) => {
      const contentStr = section.trim();
      if (!contentStr) return;
      html += `
<div class="mdp-gallery-item">

${contentStr}

</div>
`;
    });
    html += `</div>\n\n`;
    return html;
